-- Insert the detailed profiles for the 7 new users
ON CONFLICT (user_id) DO UPDATE SET 
  religion_name = EXCLUDED.religion_name, caste_name = EXCLUDED.caste_name, manglik = EXCLUDED.manglik, profile_for = EXCLUDED.profile_for, 
  managed_by = EXCLUDED.managed_by, degree = EXCLUDED.degree, employed_in = EXCLUDED.employed_in, occupation = EXCLUDED.occupation, 
  annual_income = EXCLUDED.annual_income, city = EXCLUDED.city, state = EXCLUDED.state, country = EXCLUDED.country, 
  family_type = EXCLUDED.family_type, height = EXCLUDED.height, weight = EXCLUDED.weight, marital_status = EXCLUDED.marital_status::marital_status_enum, 
  about_me = EXCLUDED.about_me, status = EXCLUDED.status::profile_status_enum;
